@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @oninput="OnSearchInput"
           value="@_query" />

    @if (_isLoading)
    {
        <div class="product-search__status">Searching…</div>
    }
    else if (_error is not null)
    {
        <div class="product-search__error">
            <span>Search failed: @_error</span>
            <button @onclick="RetrySearch">Retry</button>
        </div>
    }
    else if (_hasSearched && _results.Count == 0)
    {
        <div class="product-search__status">No products found.</div>
    }
    else if (_results.Count > 0)
    {
        <div class="product-search__results">
            @foreach (var product in _results)
            {
                <div class="product-card" @onclick="() => SelectProduct(product)">
                    <img class="product-card__image" src="@product.ImageUrl" alt="@product.Name" />
                    <div class="product-card__info">
                        <span class="product-card__name">@product.Name</span>
                        <span class="product-card__price">@product.Price.ToString("C")</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string _query = string.Empty;
    private List<Product> _results = new();
    private bool _isLoading;
    private bool _hasSearched;
    private string? _error;

    private CancellationTokenSource? _debounceCts;
    private CancellationTokenSource? _searchCts;
    private Timer? _debounceTimer;

    private void OnSearchInput(ChangeEventArgs e)
    {
        _query = e.Value?.ToString() ?? string.Empty;

        // Cancel any pending debounce and in-flight search.
        _debounceCts?.Cancel();
        _debounceCts?.Dispose();
        _debounceCts = new CancellationTokenSource();

        _debounceTimer?.Dispose();

        if (string.IsNullOrWhiteSpace(_query))
        {
            ResetState();
            return;
        }

        var linkedCts = _debounceCts;
        _debounceTimer = new Timer(_ =>
        {
            if (!linkedCts.IsCancellationRequested)
            {
                InvokeAsync(() => ExecuteSearch(_query));
            }
        }, null, 300, Timeout.Infinite);
    }

    private async Task ExecuteSearch(string query)
    {
        // Cancel any previous in-flight search.
        _searchCts?.Cancel();
        _searchCts?.Dispose();
        _searchCts = new CancellationTokenSource();
        var ct = _searchCts.Token;

        _isLoading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var results = await ProductService.SearchAsync(query, ct);

            // If this search was cancelled while awaiting, discard the results.
            ct.ThrowIfCancellationRequested();

            _results = results;
            _hasSearched = true;
        }
        catch (OperationCanceledException)
        {
            // Superseded by a newer search — do nothing.
            return;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _results = new();
        }
        finally
        {
            if (!ct.IsCancellationRequested)
            {
                _isLoading = false;
            }
        }

        StateHasChanged();
    }

    private async Task RetrySearch()
    {
        if (!string.IsNullOrWhiteSpace(_query))
        {
            await ExecuteSearch(_query);
        }
    }

    private async Task SelectProduct(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private void ResetState()
    {
        _searchCts?.Cancel();
        _results = new();
        _isLoading = false;
        _hasSearched = false;
        _error = null;
    }

    public void Dispose()
    {
        _debounceTimer?.Dispose();
        _debounceCts?.Cancel();
        _debounceCts?.Dispose();
        _searchCts?.Cancel();
        _searchCts?.Dispose();
    }
}

